(window.webpackJsonp=window.webpackJsonp||[]).push([[128],{1804:function(n){n.exports=JSON.parse('{"content":"<blockquote>\\n<p>pubsub-js: \u4e00\u4e2a\u7528 JavaScript \u7f16\u5199\u7684<code>\u57fa\u4e8e\u4e3b\u9898</code>\u7684\u53d1\u5e03/\u8ba2\u9605\u5e93</p>\\n</blockquote>\\n<hr>\\n<p><code>pubsub-js</code>\u4ee3\u7801\u91cf\u4e0d\u5927\uff0c\u4ee3\u7801\u903b\u8f91\u4e5f\u8f83\u7b80\u5355\uff0c\u4e5f\u786e\u5b9e\u5b8c\u6210\u4e86\u4e00\u4e2a\u53d1\u5e03\u8ba2\u9605\u5e93\uff0c\u57fa\u4e8e<code>javascript</code>\u7684<code>key:value</code>\u666e\u901a\u5bf9\u8c61\u3002</p>\\n<p>\u4ee3\u7801\u7ed3\u6784</p>\\n<pre class=\\"hljs\\"><code>messages={\\n   <span class=\\"hljs-attr\\">topic1</span>:{\\n        <span class=\\"hljs-attr\\">token1_1</span>:<span class=\\"hljs-built_in\\">Function</span>,\\n        <span class=\\"hljs-attr\\">token1_2</span>:<span class=\\"hljs-built_in\\">Function</span>,\\n    }, \\n   <span class=\\"hljs-attr\\">topic2</span>:{\\n        <span class=\\"hljs-attr\\">token2_1</span>:<span class=\\"hljs-built_in\\">Function</span>,\\n        <span class=\\"hljs-attr\\">token2_2</span>:<span class=\\"hljs-built_in\\">Function</span>,\\n        ...\\n    }, \\n    ...\\n}\\n</code></pre>\\n<p>\u8fd9\u4e2a<code>\u57fa\u4e8e\u4e3b\u9898</code>\u7ed3\u6784\uff0c\u5141\u8bb8\u5bf9\u540c\u4e00\u4e2a\u4e3b\u9898\u8fdb\u884c\u591a\u6b21\u4e0d\u540c\u7684\u8ba2\u9605\uff0c\u56e0\u6b64\u6bcf\u6b21\u8ba2\u9605\u4f1a\u8fd4\u56de\u4e00\u4e2a<code>token</code>\u53ef\u4ee5\u901a\u8fc7<code>unsubscribe</code>\u5bf9\\n<code>token</code>\u53d6\u6d88\u8ba2\u9605\uff0c</p>\\n<p><code>unsubscribe</code>\u4e5f\u63a5\u6536<code>topic</code>(\u4e3b\u9898\u7684\u540d\u79f0)\uff0c\u5bf9\u5f53\u524d\u4e3b\u9898\u4e0b\u6240\u6709<code>token</code>\u53d6\u6d88\u8ba2\u9605\uff0c\u4e5f\u63a5\u6536<code>function</code>\uff0c\u5220\u9664\u6240\u6709\u4e0e\u53c2\u6570\u4e00\u81f4\u7684\u8ba2\u9605\u51fd\u6570\u3002</p>\\n<p>\u540c\u65f6<code>pubsub-js</code>\u4e5f\u63d0\u4f9b\u4e86\u5c42\u7ea7\u8ba2\u9605\uff0c\u901a\u8fc7<code>.</code>\u8fdb\u884c\u5206\u7ea7\uff0c\u4f8b\u5982\u5f53\u8ba2\u9605\u4e86<code>a</code>\u548c<code>a.b</code>\u65f6\uff0c\u53d1\u5e03<code>a.b</code>\u540c\u65f6\u4e5f\u4f1a\u89e6\u53d1<code>a</code>\u7684\u8ba2\u9605\uff0c\u800c\u901a\u914d\u7b26<code>*</code>\u5219\u8868\u793a\u4efb\u4f55\u53d1\u5e03\u90fd\u5c06\u89e6\u53d1\u5b83\u7684\u8ba2\u9605\u3002</p>\\n<blockquote>\\n<p><strong>\u6ce8\u610f\uff1a<code>pubsub-js</code>\u662f\u4e00\u4e2a\u7b80\u5355\u7684\u53d1\u5e03\u8ba2\u9605\u5e93\uff0c\u5e76\u4e0d\u80fd\u89e3\u51b3\u771f\u6b63\u7684\u5f02\u6b65\u95ee\u9898\u3002</strong></p>\\n</blockquote>\\n<hr>\\n<p>\u601d\u7ef4\u5bfc\u56fe\uff1a\\n<img src=\\"https://stonehank.github.io/articles/img/PubSub.png\\" alt=\\"\\"></p>\\n"}')}}]);